framework_css:
/* Root design tokens */
:root {
  --color-primary-900: #000000;
  --color-primary-700: #333333;
  --color-secondary-500: #777777;
  --color-bg-page: #f2f2f2;
  --color-bg-surface: #ffffff;
  --color-border-subtle: #dddddd;
  --color-link: #1155cc;
  --color-link-hover: #0073e6;
  --color-success: #2e7d32;
  --color-error: #c62828;
  --color-warning: #ed6c02;
  --color-info: #1565c0;

  --font-logo: "Great Vibes", "Brush Script MT", cursive;
  --font-heading: "Playfair Display", Georgia, "Times New Roman", serif;
  --font-body: "Lora", Georgia, "Times New Roman", serif;
  --font-nav: "Helvetica Neue", Arial, sans-serif;
  --font-code: "Source Code Pro", Menlo, Consolas, monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --layout-max-width: 980px;
}

/* Global reset / base */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  background-color: var(--color-bg-page);
  color: var(--color-primary-700);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
  margin-top: 0;
  font-family: var(--font-heading);
  color: var(--color-primary-900);
  line-height: var(--line-height-tight);
}

h1 {
  font-size: var(--font-size-h1);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-3);
}

small {
  font-size: var(--font-size-small);
}

/* Links */
a {
  color: var(--color-link);
  text-decoration: underline;
}

a:hover,
a:focus {
  color: var(--color-link-hover);
}

a:focus-visible {
  outline: 2px solid var(--color-link-hover);
  outline-offset: 2px;
}

/* Layout shells */
.site-header {
  background-color: var(--color-bg-surface);
  border-bottom: 1px solid var(--color-border-subtle);
}

.site-header-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3) var(--space-3);
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
}

/* Logo */
.site-branding {
  flex: 1 1 auto;
}

.site-title {
  font-family: var(--font-logo);
  font-size: 32px;
  line-height: 1;
  color: var(--color-primary-900);
  text-decoration: none;
  white-space: nowrap;
}

/* Primary navigation */
.primary-nav {
  flex: 0 0 auto;
}

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  gap: var(--space-4);
}

.primary-nav-item {
}

.nav-link {
  font-family: var(--font-nav);
  font-size: 12px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--color-secondary-500);
  text-decoration: none;
  padding-bottom: 2px;
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-primary-700);
  text-decoration: none;
}

.nav-link.is-active {
  color: var(--color-primary-900);
}

/* Main content layout */
.site-main {
  background-color: var(--color-bg-page);
}

.site-main-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-3) var(--space-6);
  background-color: var(--color-bg-surface);
  display: flex;
  align-items: flex-start;
}

/* Content area */
.content-main {
  flex: 0 0 66%;
  min-width: 0;
}

/* Sidebar */
.content-sidebar {
  flex: 0 0 34%;
  padding-left: var(--space-5);
  border-left: none;
  font-size: 14px;
  line-height: var(--line-height-normal);
  color: var(--color-primary-700);
}

.content-sidebar h2,
.content-sidebar h3 {
  font-size: 16px;
  margin-bottom: var(--space-2);
}

.content-sidebar section + section {
  margin-top: var(--space-4);
}

/* Footer */
.site-footer {
  background-color: var(--color-bg-surface);
  border-top: 1px solid var(--color-border-subtle);
}

.site-footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: var(--font-size-small);
  color: var(--color-secondary-500);
}

.footer-meta {
  margin: 0;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  gap: var(--space-3);
}

.footer-nav a {
  color: var(--color-secondary-500);
  text-decoration: none;
}

.footer-nav a:hover,
.footer-nav a:focus {
  color: var(--color-primary-700);
  text-decoration: underline;
}

/* Code blocks */
code, pre {
  font-family: var(--font-code);
}

/* Responsive adjustments */
@media (max-width: 768px) {
  .site-header-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-3);
  }

  .primary-nav-list {
    gap: var(--space-3);
    flex-wrap: wrap;
  }

  .site-main-inner {
    flex-direction: column;
  }

  .content-main {
    flex-basis: auto;
  }

  .content-sidebar {
    flex-basis: auto;
    padding-left: 0;
    margin-top: var(--space-5);
  }

  .site-footer-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-2);
  }
}
